import React, { useEffect,useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, CFormLabel} from "@coreui/react";
import FormInput from '../../utils/FormInput';
import GoBackComponent from 'src/utils/GoBackComponent';
import { createSubscriptionPlan, getPlanById, updateSubscriptionPlan } from 'src/components/services/SubscriptionPlanApi';
import TextArea from 'src/utils/TextArea';
import authService from 'src/auth/auth.service';
import Select from 'react-select';
import { planOptions } from 'src/utils/Common';


const SubscriptionPlanForm = (props) => {

    const navigate = useNavigate();
    const { type,id } = props;
    const [errors, setErrors] = useState({});
    const [inputFieldValue, setInputFieldValue] = useState({ planType: '', planAmount: '', description:  ''});
    const [errorMessage, setErrorMessage] = useState();
    const [subscriptionPlan, setSubscriptionPlan] = useState({});

    useEffect(() => {
        if(type === "UPDATE"){
            fetchSubscriptionPlanDetailsById(id);
        }

    },[])

    const handleChange = (event) => {
        setInputFieldValue((inputField) => ({ ...inputField, [event.target.name]: event.target.name === "planType"  ? event.target.value.trimStart()?.replace(/[^a-zA-Z ]/g, "") : event.target.name === "planAmount" ? event.target.value.trimStart()?.replace(/[^\d\.]*/g, '') : event.target.value.trimStart() }));
    }

    const handleSelectPlan = (value) => {
        setSubscriptionPlan(value)
    }

    const fetchSubscriptionPlanDetailsById = async() => {
        let response =  await getPlanById(id) 
            if(response?.message === "Success!") {
                let productDetails = response?.body;
                setSubscriptionPlan({value: response?.body?.subscriptionPlanType, label: response?.body?.subscriptionPlanType})
                setInputFieldValue((prevInputField) => ({...prevInputField ,planAmount: response?.body?.amount, description: response?.body?.description}));
            }
    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        if (!subscriptionPlan?.value) {
            errors['planType'] = "Please select plan type";
            formIsValid = false;
        }
        if(!inputFieldValue?.planAmount) {
            errors['planAmount'] = "Please enter plan amount";
            formIsValid = false;
        }
        if(!inputFieldValue?.description) {
            errors['description'] = "Please enter description";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                subscriptionPlanType: subscriptionPlan?.value,
                amount: inputFieldValue?.planAmount,
                description: inputFieldValue?.description,
                ...(id && { id: id })
            }
            let response = {};
            if(type === "CREATE"){
                response = await createSubscriptionPlan(postData)
            }else{
               response =  await updateSubscriptionPlan(postData)
            }
            if(response?.status === "201 CREATED" || response?.status === "202 ACCEPTED") {
                navigate("/subcription-plan");
            }
            if(response?.status === "409 CONFLICT") {
                setErrorMessage(response?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            }, 3000)
        }
    };


    return (
        <>
            <GoBackComponent goBackData={"subcription-plan"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <CFormLabel >Plan type<span className="text-danger">*</span></CFormLabel>
                        <Select
                            options={planOptions}
                            placeholder={"Select Plan"}
                            value={subscriptionPlan}
                            onChange={handleSelectPlan}
                            classNamePrefix="select"
                            styles={{
                                option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                    const color = '#03a68059';
                                    return {
                                        ...styles,
                                        backgroundColor: isDisabled ? null : isSelected ? '#03a68059' : isFocused ? '#03a68059': null,
                                        color: isDisabled? '#ccc' : isSelected ? color > 2 ? '#00374d' : '#00374d' : data.color, cursor: isDisabled ? 'not-allowed' : 'default',
                                        ':active': { ...styles[':active'], backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059')},
                                    }
                                },
                                control: (provided, state) => ({...provided, minHeight: '50px', width: "100% ", borderRadius:'8px' , borderColor: state.isFocused ? '#03a680' : '#ced4da',}),
                            }}
                        />
                        {errors["planType"] && <span style={{color: 'red'}}>{errors["planType"]}</span>}
                    </CCol>
                    <CCol md={8}>
                        <FormInput
                            value={inputFieldValue?.planAmount}
                            label={"Plan amount"}
                            name={"planAmount"}
                            onChange={handleChange}
                            required={true}
                            error={errors['planAmount']}
                        />
                    </CCol>
                    <CCol md={12}>
                        <TextArea
                            value={inputFieldValue?.description}
                            label={"Description"}
                            name={"description"}
                            onChange={handleChange}
                            required={true}
                            error={errors['description']}
                        />
                    </CCol>
                    {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    {authService.getPermission(type === "CREATE" ? "SUBSCRIPTION_PLAN_CREATE" : "SUBSCRIPTION_PLAN_UPDATE") && 
                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {type === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>}
                </CForm>
            </div>
        </>
    );
}

export default SubscriptionPlanForm;
